export function getFactionFlagFromLeaderboardId(leaderboardId: number): string {
	const leaderboardRaceMap: Record<number, Race> = {
		4: Race.US,
		8: Race.US,
		12: Race.US,
		16: Race.US,
		5: Race.Wehrmacht,
		9: Race.Wehrmacht,
		13: Race.Wehrmacht,
		17: Race.Wehrmacht,
		6: Race.Commonwealth,
		10: Race.Commonwealth,
		14: Race.Commonwealth,
		18: Race.Commonwealth,
		7: Race.PanzerElite,
		11: Race.PanzerElite,
		15: Race.PanzerElite,
		19: Race.PanzerElite,
		0: Race.US,
		1: Race.Wehrmacht,
		2: Race.Commonwealth,
		3: Race.PanzerElite,
		42: Race.US,
		43: Race.Wehrmacht,
		44: Race.Commonwealth,
		45: Race.PanzerElite,
		54: Race.US,
		55: Race.Wehrmacht,
		46: Race.US,
		47: Race.Wehrmacht,
		50: Race.US,
		51: Race.Wehrmacht
	};
	const race = leaderboardRaceMap[leaderboardId];
	return getFactionFlagFromRace(race);
}

