	$230100: 'Take cover!',
	$230110: 'MG42! Second floor!',
	$230120: 'Shelby get that B.A.R going, keep their heads down!',
	$230121: 'Shelby get that B.A.R going, keep their heads down!',
	$230130: 'Find some cover... were taking enfilade fire!',
	$230131: 'Find some cover... were taking enfilade fire!',
