	$309704: 'XXXX Another TERRITORY is ours! Keep it up!',
	$309705: 'XXXX Look at them run. Filthy cowards!',
	$309706: "XXXX We gott'em on the run boys! Pour it on!",
	$309707: "XXXX They're pulling back. Quickly, advance!",
	$309708: "XXXX Hit'em with everything you got!",
	$309709: "XXXX Look! They're retreating as we capture their territories!",
	$309710: "XXXX All right, well let's capture more territories!",
