	$320370: "Goddamn PANTHER!  We can't hurt that!",
	$320380: "We're taking HEAVY FIRE from that PANTHER.",
	$320400: 'PANTHER destroyed... kill confirmed!',
	$320401: 'PANTHER destroyed... kill confirmed!',
