	$320411: 'Gunner... PANTHER is KNOCKED OUT.',
	$320420: 'Hell ya, Panther kill confirmed!',
	$320421: 'Hell ya, Panther kill confirmed!',
	$320430: 'Sir... Panther Target is smoking.',
	$320431: 'Sir... Panther Target is smoking.',
	$320440: 'Direct Hit! Panther is history.',
	$320441: 'Direct Hit! Panther is history.',
