	$6001070: 'Radio Operator',
	$6001080: 'Schutze Alfred Litzke',
	$6001090: 'Loader',
	$6010490: 'Achtung Tigergruppe!',
	$6010501: "The fools act as if they've won the war already.",
	$6010511: "We'll prove them wrong!",
