	$6010532: 'Shultz, target enemy panzers and paks.',
	$6010534: 'Make every round count.',
	$6010536: 'Strike hard and clear the village of all enemy armor.',
	$6010550: 'Motor to four hundred PS!',
	$6010560: 'More! Schnell!',
	$6010570: 'Contact.',
	$6010580: 'Loading round.',
	$6010590: 'For the fatherland, men! Destroy the British! Fire at Will!',
