	$6010890: '33 kills. We cleared the place out!',
	$6010900:
		"5 Wagen. 4 Schützenpanzer. 3 Spielzeugpanzer 12 Cookers. 3 Fireflies and 4 Paks! That's 34! 34 kills!",
	$6010910: '35 kills. We cleared the place out!',
	$6010920: '36 kills. We cleared the place out!',
	$6010930: '37 kills. We cleared the place out!',
	$6010940: '38 kills. We cleared the place out!',
	$6010950: '39 kills. We cleared the place out!',
	$6010960: '40! 40 kills! Heilige Scheisse!',
	$6010970: '(howling like a wolf)',
	$6010980: '(howling like a wolf)',
	$6010990: 'Ask the grenadiers to confirm our count on their way in!',
	$6011000: "Skill like this doesn't come easy!",
	$6011010: 'On it.',
	$6011020: "I'm on it.",
