	$6011140: "We've lost hydraulic takeoff, Hauptmann, sir.",
	$6011150: 'The motor has stalled out. Just give me a moment.',
	$6011160: "If we keep moving, we'll fry the engine. Let me figure it out!",
	$6011170: 'Verdammt noch mal! Get it fixed! Mach schnell!',
	$6011180: 'Yes, Herr Hauptmann!',
	$6011181: 'Verflixte Frenchmen pissing on our tank.',
	$6011190: 'Checking manifold pressure!',
	$6011200: 'Gearbox in order.',
