	$6011440: 'Shot out.',
	$6011450: 'Berndt, radio HQ, the Stahlvormund has two more kills.',
	$6011460: 'Jawohl, I have a Pak one kilometer out.',
	$6011490: 'Engage.',
	$6011500: 'Turning turret. Load round.',
	$6011510: 'Round loaded.',
	$6011520: 'It was there on the Eastern Front we made a name for ourselves.',
	$6011530: 'By the spring of forty-four we had been redeployed to the Western front, France.',
	$6011540:
		'I gave orders to move at first light, directing the bulk of my Panzer Company ahead to point 213.',
	$6011550: 'The Stahlvormund was moving slowly -- we had engine trouble.',
	$6011560: 'Brand new motor and it runs like scheisse.',
	$6011570: 'Just keep the turret powered.',
	$6011580: "Great! A turret for targets we can't reach!",
