	$9391740: 'Falaise Pocket',
	$9394050: 'The US 90th Division has been repelled for now.',
	$9394051: 'The Panzer Division has been crushed.',
	$9394504: 'Report to the Church',
	$9394505: 'Alert Hauptmann Funke at the Church. He must be alerted of the possible invasion.',
	$9394506: 'Hauptmann Alerted',
	$9394507: 'Build 88 Emplacement',
	$9394508:
		'Order the Luftwaffe to build at least one 88 emplacement and protect the church from Allied Aircraft.',
	$9394509: '88 Emplacement Built',
	$9394510: 'Alert the Garrisons',
	$9394511: 'Rouse the soldiers within the garrisons and alert them of the incoming Allies.',
	$9394512: 'All Garrisons Alerted',
	$9394513: 'Intercept Allied Recon',
	$9394514: 'Stop the Allied recon forces before they locate the Panzers.',
	$9394515: 'Allied Recon Forces Elliminated',
	$9394516: 'Shield the Panzers',
	$9394517:
		'Keep the Panzers free from Allied harassment.  Ensure that the paratroopers and planes do not find them.',
	$9394518: 'Panzers Protected',
	$9394519: 'Stop the Allied recon forces from destroying the Panzers.',
	$9394525: 'Prevent Any Panzer Casualties',
	$9394526: 'Do not let any harm come to the Panzer division. Not a single tank can be lost.',
	$9394527: 'No Panzers Lost',
