	$9404616: 'Man the Nebelwerfer',
	$9404617: 'Man the Pak 38',
	$9404618: 'Defend South Crossing',
	$9404619: 'Defend North Crossing',
	$9404620: 'Defend the Crossroads',
	$9404621: 'Block Crossing with Tank Traps',
	$9404622: 'Incoming Artillery',
	$9404623: 'Canadian artillery batteries are opening fire',
	$9404624: 'American artillery batteries are opening fire',
	$9404625: 'Bridge Being Repaired',
	$9404626: 'Stop the engineers from repairing the bridge',
	$9404627: 'Bridge Repaired',
